DROP TABLE IF EXISTS `ph_addresses_vw`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `ph_addresses_vw` AS SELECT 
b.iid brgy_id,
b.iname brgy_name,
b.icode brgy_icode,
b.brgy_logo brgy_logo,
c.iid city_id,
c.iname city_name,
c.icode city_icode,
c.city_logo city_logo,
p.iid province_id,
p.iname province_name,
p.icode province_icode,
p.province_logo province_logo,
r.iid region_id,
r.iname region_name,
r.icode region_icode
FROM ph_barangays b
JOIN ph_cities c ON (b.city_id=c.iid)
